// src/App.jsx
import './index.css';

export default function App() {
  const cities = [
    { city: 'Atlanta', temp: 30, condition: 'Sunny' },
    { city: 'Chicago', temp: 22, condition: 'Cloudy' },
    { city: 'New York', temp: 26, condition: 'Rain' },
  ];

  return (
    <div className="min-h-screen bg-white text-gray-800 relative">
      <div className="flex flex-col items-center justify-center gap-8 pt-24 pb-32">
        <h1 className="text-4xl font-bold text-purple-800">Weather App</h1>
        <div className="flex flex-wrap justify-center gap-6">
          {cities.map((data) => (
            <div
              key={data.city}
              className="backdrop-blur-md bg-purple-200/30 border border-white/30 rounded-2xl shadow-md p-6 w-64 text-center transition-transform hover:scale-105"
            >
              <h2 className="text-xl font-semibold text-purple-900">{data.city}</h2>
              <p className="text-4xl font-bold text-purple-800">{data.temp}°C</p>
              <p className="text-sm text-purple-600">{data.condition}</p>
            </div>
          ))}
        </div>
      </div>

      {/* Bottom Bar */}
      <nav className="fixed bottom-0 left-0 w-full bg-white/30 backdrop-blur-md border-t border-white/20 flex justify-around py-4 shadow-lg">
        {['Chatbot', 'Community', 'Radar'].map((item) => (
          <button
            key={item}
            className="text-purple-700 font-semibold hover:underline"
          >
            {item}
          </button>
        ))}
      </nav>
    </div>
  );
}
